// Script Continued Below
function onLoad() {
	// 2.6 - STRY0095470 - Task Order should only appear on subtasks with more than on sibling
	// failed for top task on duration modal b/c there was no parent
	// DFCT0011168  - fixed issue Task Order was not showing up on create until the 3rd item was created.
	var displayTaskOrder = false;
	if(g_scratchpad.numberOfParentChildren && 
		(parseInt(g_scratchpad.numberOfParentChildren) > 1) ||
		(g_form.isNewRecord() && parseInt(g_scratchpad.numberOfParentChildren)>0)){
		displayTaskOrder = true;
	}
	if(g_form.getControl('task_order')){
		g_form.setDisplay('task_order',displayTaskOrder);
	}
}
